const items = $input.all();

// Agar data khali aaye toh empty return karein
if (!items || items.length === 0) {
  return [];
}

// Top level ke liye pehle item se MCAT details nikal lete hain
const mcatId = items[0].json.mcat_id;
const mcatName = items[0].json.mcat_name;

// Specs ko group aur count karne ke liye ek map banayenge
const specsMap = {};

items.forEach(item => {
  const data = item.json;
  const specName = data.spec_name;
  const optionValue = data.option_value;

  // Check karte hain ki spec name exist karta hai
  if (specName) {
    // Agar ye spec pehli baar aaya hai, toh object banayein count 0 ke sath
    if (!specsMap[specName]) {
      specsMap[specName] = {
        options: [],
        count: 0
      };
    }

    // Har baar jab ye spec mile, iska count +1 kar dein
    specsMap[specName].count += 1;

    // Duplicate options ko avoid karne ke liye check karte hain
    if (optionValue !== undefined && !specsMap[specName].options.includes(optionValue)) {
      specsMap[specName].options.push(optionValue);
    }
  }
});

// Map ko ek clean Array of Objects mein convert karte hain
const groupedSpecs = Object.keys(specsMap).map(key => {
  return {
    spec_name: key,
    count: specsMap[key].count, // Naya field: Spec kitni baar aaya
    options: specsMap[key].options
  };
});

// Final Output return karte hain
return [{
  json: {
    mcat_id: mcatId,
    mcat_name: mcatName,
    custom_specs: groupedSpecs
  }
}];

const specs = [];

const fs = items[0].json.finalized_specs;

fs.finalized_primary_specs.specs.forEach(s => {
  if (s.options) {
    specs.push({ spec_name: s.spec_name, spec_options: s.options.slice(0, 6) });
  }
});

fs.finalized_secondary_specs.specs.forEach(s => {
  if (s.options) {
    specs.push({ spec_name: s.spec_name, spec_options: s.options.slice(0, 6) });
  }
});

fs.finalized_tertiary_specs.specs.forEach(s => {
  if (s.options) {
    specs.push({ spec_name: s.spec_name, spec_options: s.options.slice(0, 6) });
  }
});

return [{
  json: {
    category: items[0].json.category_name,
    platform_specs: specs
  }
}];

// Input: $json is each item returned by Fetch Spec / normalizer
// Output: { mcat_id, finalized_spec_url }

const out = [];
const item = $json; // current batch item

// helper to safely read nested path
function get(obj, path, def = undefined) {
  return path.split('.').reduce((a, b) => (a && a[b] !== undefined) ? a[b] : def, obj);
}

const mcat_id = item.mcat_id || get(item, 'mcatId') || null;

// Try the canonical path: finalized_specs.file_info.url
let url = get(item, 'finalized_specs.file_info.url');

// fallback: sometimes file_info might be array, or finalized_specs may be null
if (!url) {
  // case: finalized_specs.file_info could be an array
  const fileInfo = get(item, 'finalized_specs.file_info');
  if (Array.isArray(fileInfo) && fileInfo.length > 0) {
    url = fileInfo[0].url || fileInfo[0].download_url || null;
  }
}

// ultimate fallback: search object for any https://storage.googleapis.com/... occurrence
if (!url) {
  const jsonStr = JSON.stringify(item);
  const m = jsonStr.match(/https:\/\/storage\.googleapis\.com\/[^\s"']+/);
  if (m) url = m[0];
}

return [{ json: { mcat_id, finalized_spec_url: url || null } }];
