items.forEach(item => {
  if (item.json && item.json.custom_specs) {

    // Filter lagakar sirf wahi specs rakhte hain jinka count 5 ya usse zyada hai
    item.json.custom_specs = item.json.custom_specs.filter(spec => {
      // Agar count missing hai toh 0 maan lein
      const count = spec.count || 0;
      return count >= 5; 
    });

  }
});

// Cleaned data wapas return kar dete hain
return items;

