      normalized_results: parsedData
    };
  }

  // 5. Data ko n8n format mein return karein
  return [{
    json: parsedData
  }];

} catch (error) {
  // 6. Agar parsing fail ho jaye
  return [{
    json: {
      error: "AI Response Parsing Failed",
      message: error.message,
      raw_output: aiResponse 
    }
  }];
}

// 1. Current data (AI ka clean output jisme merged_from hai)
const aiData = $input.first().json;

// 2. TIME MACHINE: Original data uthate hain jisme counts aur options the
// Screenshot ke hisaab se us node ka naam 'Code in JavaScript1' hai.
const originalItems = $items("Code in JavaScript1");

if (!originalItems || originalItems.length === 0) {
  throw new Error("Could not find data from 'Code in JavaScript1'. Please check the node name.");
}

const originalSpecs = originalItems[0].json.custom_specs || [];

// 3. Original specs ki ek fast lookup dictionary banate hain
const originalSpecsMap = {};
originalSpecs.forEach(spec => {
  originalSpecsMap[spec.spec_name] = {
    count: spec.count || 0,
    options: spec.options || []
  };
});

// 4. AI ke data ko map karke counts aur options jodte hain
const finalSpecs = [];

// AI parser ne data jis list mein diya hai (normalized_custom_specs)
const normalizedArray = aiData.normalized_custom_specs || [];

normalizedArray.forEach(normSpec => {
  let totalCount = 0;
  let combinedOptions = [];

  // Har us original spec (merged_from) ko dhoondhte hain jo is group mein aaya hai
  if (normSpec.merged_from && Array.isArray(normSpec.merged_from)) {
    normSpec.merged_from.forEach(rawName => {
      // Agar wo original map mein mil gaya, toh uski details add kar do
      if (originalSpecsMap[rawName]) {
        totalCount += originalSpecsMap[rawName].count; // Count Plus (+) ho jayega
        combinedOptions.push(...originalSpecsMap[rawName].options); // Options combine ho jayenge
      }
    });
  }

  // Options ko deduplicate karte hain aur sirf Top 5 rakhte hain
  const uniqueOptions = [...new Set(combinedOptions)].slice(0, 5);

  finalSpecs.push({
    spec_name: normSpec.spec_name,
    count: totalCount,
    options: uniqueOptions
  });
});

// 5. Final array ko Count ke hisaab se sort karte hain (Highest count on top)
finalSpecs.sort((a, b) => b.count - a.count);

// 6. Ekdum clean aur perfect data return karte hain
return [{
  json: {
    mcat_id: aiData.mcat_id,
    mcat_name: aiData.mcat_name,
    custom_specs: finalSpecs
  }
}];

// 1. AI Parser (Code in JavaScript4) se aaya hua current data lijiye
const currentData = $input.first().json;

// 2. TIME MACHINE: 'Code in JavaScript3' se historical data uthaiye
const nodeName = "Code in JavaScript3"; 

let historicalData;
try {
  historicalData = $items(nodeName);
} catch (e) {
  throw new Error(`Bhai, '${nodeName}' naam ka node nahi mila. Kripya check karein!`);
}

if (!historicalData || historicalData.length === 0) {
  throw new Error("Node mil gaya par usme data nahi hai.");
}

// Pichle node se custom specs ki list nikalte hain
const allSpecsWithOptions = historicalData[0].json.custom_specs || [];

// 3. SMART MATCHING FUNCTION
// Ye function capital/small letters aur brackets ko ignore karke match karega
function findBestMatchOptions(aiName, originalSpecs) {
  const aiClean = aiName.toLowerCase().trim();

  // Step A: Exact Case-Insensitive Match (e.g., "Li-Ion" vs "Li-ion")
  let match = originalSpecs.find(s => s.spec_name.toLowerCase().trim() === aiClean);
  if (match) return match.options || [];

  // Step B: Partial Match (Agar AI ne brackets hata diye hain)
  const aiBase = aiClean.replace(/[^a-z0-9\s]/g, ''); // Special chars hata diye
  match = originalSpecs.find(s => {
      const origBase = s.spec_name.toLowerCase().replace(/[^a-z0-9\s]/g, '');
      return origBase.includes(aiBase) || aiBase.includes(origBase);
  });

  if (match) return match.options || [];

  return []; // Agar kuch bhi match na ho toh empty array
}

const enrichedMissingSpecs = [];

// 4. AI ke strings ko unke options ke sath map karte hain
if (currentData.missing_unique_specs && Array.isArray(currentData.missing_unique_specs)) {
  currentData.missing_unique_specs.forEach(missingSpecName => {

    // Smart match function se sirf options nikalte hain
    const matchedOptions = findBestMatchOptions(missingSpecName, allSpecsWithOptions);

    // YAHAN SE COUNT HATA DIYA GAYA HAI! Sirf Name aur Options jayenge.
    enrichedMissingSpecs.push({
      spec_name: missingSpecName,
      options: matchedOptions
    });
  });
}

// 5. Final JSON Return karein jo sidha Google Sheet mein append hone ke liye ready hai
return [{
  json: {
    mcat_id: currentData.mcat_id,
    mcat_name: currentData.mcat_name,
    missing_unique_specs: enrichedMissingSpecs,
    reasoning_for_rejection: currentData.reasoning_for_rejection
  }
}];
